  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Varuna Agosti', 'varuna agosti', false, 'Varuna Agosti is an Amsterdam-based DJ, producer, and Electronic Music student at the Conservatory of Amsterdam. Amsterdam-based DJ and producer Varuna Agosti explores the emotional and rhythmic possibilities of electronic music, shaping a sound that’s as fluid as it is intentional. 

Blending warm Detroit, dub, deep, hypnotic, minimal techno and house with touches of acid, electro, and ambient, she creates an atmosphere where body and mind can connect. While these influences shape her selections, she can’t be confined to a single style, instead exploring the spaces where genres overlap and merge in unexpected ways. Raised by a drummer and percussionist, she found early inspiration in rhythm and emotion, shaping her sound as is it today. 

Now studying Electronic Music at the Conservatory of Amsterdam (AEMA) while holding residencies at ORPHIC and RRFM, she is expanding her knowledge and refining her own musical voice. She has played at renowned Dutch venues like RADION, RAUM, Perron, Thuishaven and Basis, and is making her international and festival debuts later this year.', 'https://www.awakenings.com/en/artists/varuna-agosti/383015/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('DJ Red', 'dj red', false, 'Born and raised in Italy, DJ Red is a key figure of the Roman techno scene. Resident of the former iconic Goa Club, her contribution has been essential to the development of Rome’s club culture. Constantly traveling between Rome and Berlin over the past two decades, she has built up a unique approach to electronic music both as a producer and a performer. When in the DJ booth, DJ Red fully deploys her eccentric and multifaceted personality.

From Berghain, Tresor, OHM, RSO, Watergate to Awakenings and Exit Festival, Terraforma Festival, Waking Life, Ankali, Else, De School, Blitz. She never fails to deeply connect with her audience. The manic perfection in selecting every single record and the commitment of her daily research makes it impossible not to be dragged in by her intense, visionary techno sets. The thriving passion for music blossoms also in her productions. Intertwining dynamic rhythms arising from electronic drums, organic tonalities and esoteric machines, DJ Red gives birth to aethereal, aqueous soundscapes that reach the very core of her listeners. Her discography counts releases on labels such as Electric Deluxe, Wolfskuil Records, BPitch, Danza Tribale, and remixes from Ricardo Villalobos, Speedy J and Lucy (Zeitgeber), Stanislav Tolkachev, LoryD.

DJ Red is a shimmering example of techno’s past, present and future, a voice that continues to evolve alongside the genre she so proudly represents; time after time with each impressive performance.', 'https://www.awakenings.com/en/artists/dj-red/382/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Andy Martin', 'andy martin', false, 'Andy Martin is a Mexican Jamaican electronic artist who mixes up sci-fi techno and Latin Caribbean sounds with a futuristic edge.

His most recent album “Antiguos Astronautas” is a musical exploration between the sounds of techno and native american futurism narrative which had a good response from the music community with the support of artists like DVS1, Nastia, Ben UFO, Tobi Neumann, Gigi FM, Blawan, Jonas Kopp, Daniel Avery, Fred P, Electric Indigo, Batu, Darwin, Rene Wise, Marcal, Reka Zalan, DJ Rolando, Josh Wink, Luke Slater, Norman Nodge, Richie Hawtin, Dj Bone, The Advent, Truncate, Arjun Vagale, Ciel, Machine Woman, among others, playing his tracks in clubs like Berghain, Tresor, Fabric, Bassiani, Lux Fragil, De School. 

His experience and skills as a DJ has led him to perform at the best clubs and venues in México among artist like Dj Stingray, Skee Mask, Aurora Halal, Ryan Elliot, Batu, Darwin, Function, Mad Miran, NVTS, Eduardo de la Calle,Victor, Goldie among others. 

His last release on the label Mole Audio was a collaboration with the Jamaican artist legend Lee Scratch Perry who was one of the most relevant figures in dub music and an important influence on music culture.

His alternative ambient works have led him to perform in museums, art galleries, and international festivals like MUTEK in the edition of 2020 in México and Japan with his ambient album “The Language of Sound”.', 'https://www.awakenings.com/en/artists/andy-martin/382996/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Len Faki', 'len faki', false, 'His move to Berlin marked a decisive turning-point in his career. With Len Series he founded an independent platform and trademark for his idea of Techno music. The basic concept including sublabels allows him to explore musical depths and artistic freedom.  His strong appearances at venues like Tresor and Ostgut (Berlin) culminated in his residency at Berghain (the former Ostgut), a position which further fueled his open-minded approach as both DJ and producer. The characteristic extra-long DJ sets force him to vary in tone, style and feed him with extra inspiration.  At Berghain, he also launched the Podium night, a quarterly event where he invites his appreciated colleagues from all over the world. This step also resulted in the birth of his sublabel Podium with releases by Raudive (aka Oliver Ho) or Shinedoe. Right with his first offshoot, he stormed the cases and charts of top DJs/producers such as Luke Slater, Sven V..th and Ivan Smagghe.  While figure sees his own releases in loose combination with artist’s remixes, Podium features exclusive artist releases in combination with his own work. Whereas figure is like heavy tropical rain, Podium appears like a sharply defined sky after the downpour. Both labels stand for cutting-edge Techno music.  His bone-dry but communicative DJ style marks him as a true gentleman behind the turntable, an artist whose sets are based on passion and beauty. His finger tips are like sensors on the Richter scale, and anticipate as well as trigger eruptions on the floor...', 'https://www.awakenings.com/en/artists/len-faki/870/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Quest', 'quest', false, 'Quest, class of 1992, influenced by the Alien army and by the special technique of shadowboxing... Head of La Nota Del Diablo.. Like the Beast, it goes by many names: Diabolus in musica (devil in music), the devil''s interval, the tritone, the triad and the flatted fifth. As its Latin moniker suggests, it''s an evil sounding combination of notes that''s designed to create a chilling or foreboding atmosphere.. an atmosphere that characterizes his sets showcasing a vast collection of unearthed genre bending gems ranging across the electronic spectrum from outrè techno to electro to EBM', 'https://www.awakenings.com/en/artists/quest/215026/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Planetary Assault Systems', 'planetary assault systems', false, '“I want this music to be quite relentless, tough and raw”
On his latest LP, the influential British techno producer Luke Slater decided to go ‘Skyscraping.’ Following up 2021’s self-explanatory ‘Say it Loud’ album on Token, the ten track digital collection included killer cuts like ‘Labstract’, ‘One For The Groove’ and ‘The Drag Train’ and was also available on liquorice pizza, the format known to some more vintage listeners as the vinyl long player. And on that superb new ten track long player,
Slater draws not only on studio material but also components recorded during the acclaimed Planetary Assault live show – and he’s keen to let fans know that the focus is well and truly on the dance-floor. ‘Sky Scraping’ is a loud and unashamedly upbeat celebration of the formative and familiar environments so loved by the electronic music community, the clubs and festivals made special by that unique ability of bringing people together. And released via Token, the Belgian label who celebrated their 100th release with Luke with the booming EP opener ‘Bang Wap’. Resident Advisor described the track as “PAS at its most elemental” and later included it in their round-up of the year’s key releases.

A phrase that comes up a lot is “have I got something to say?” so and for the best part of an hour, Slater most definitely does. “Before I started writing, there was there was some great music in the UK dance music. Well-produced and with the melody in the right places. But I wanted something a bit more ballsy and with drive. I kind of wanted that in the records. I remember when Jeff Mills released an EP as Final Cut and I remember listening to that and thinking: “wow, so this means it really can be that hard!”

When we speak late December to talk music, life and new adventures, Luke is at home near Horsham where he now lives: West Sussex to be precise. “I think that''s one of the weird things I enjoy the most about living around here,” he smiles. “Absolutely no one understands anything about what you do so I’m kind of incognito! Occasionally an older tradesman will say they went to Tribal Gathering back in 1991 but that’s it. Which is a beautiful thing, I guess.”

A key player on the UK (and now global) techno scene, Luke Slater has been a firm fixture on all the right electronic line-ups since the early nineties, and like fellow electronic visionaries and sonic sorcerers like Sven Väth and Richie Hawtin, he’s never stopped to smell the proverbial roses. Born in Berkshire, he’s a major player with a sound and (punk)attitude that’s impossible to miss and yet despite all of that success, he’s always kept his artistic feet on the ground. That’s extremely evident as we chat over Zoom for this new interview as 2022 comes into view. “I think I''ve got more fire now than it had in the beginning. And I like that. I remember talking to Derrick May back in the 90s at a café in Belgium and all we talked about was the hunger. And the hunger was born out of the life you''ve lived, how you grew up and what you went through. And the situation for me growing up, although I didn''t have a bad upbringing, it was flippin’ hard, man. The world was not how I wanted it to be and I didn''t fit in. People romanticize the 90s but the path was not easy. I don''t want to be bogged down by the rules. Society. And unfortunately, that''s something that''s even stronger in me now.” 

A bona fide pioneer of sound design and performance with a singular musical vision, Slater first minted the P.A.S. alias back in 1993. Since then, Planetary Assault Systems has become a byword for hypnotic, soulful and funk-heavy techno that blurs the lines between pure psychedelic and peak-time, main room techno for audiences large and small. Whatever the environment, Luke Slater’s work as Planetary Assault Systems captures the very best elements of techno for audiences across the globe. Crucially, this is music with a huge vision and scope, meaning Luke has fans across the world, from London and Berlin to Detroit via Dekmantel and back. It’s no accident that his latest album comes to a close with the classic sonics of ‘Nano Chameleon’: this futuristic, forceful slice of funk is powered by white noise percussion and never lets go for a minute. It’s the same spiritual ethos that has powered Luke’s own mind-set since the early days and it’s no accident that he’s been called “one of techno’s most chameleonic enigmas” in the past. And when you’ve released on labels from NovaMute and Ostgut Ton to Peacefrog and his own Mote-Evolver imprint, you’d be a fool to argue against the karmic chameleon.


As an artist, he also used different monikers for different musical lanes: L.B. Dub Corp and the aforementioned Planetary Assault Systems to The 7th Plain and of course his own forays into artist albums on NovaMute as Luke Slater and in 2020 he released ‘Berghain Funfzehn’ which looped and tweaked sounds from the acclaimed Ostgut Ton imprint and created killer new compositions as a result. Looking ahead, it’s clear that Luke the early solo misfit still feels like he has a considerable amount of musical goodness left to give. As a remixer, his musicality has made its way onto oodles of global icons, from fellow former Mute icons Depeche Mode and Octave One to Kenny Larkin, Madonna and Daniel Avery, who enlisted Luke to remix ‘Diminuendo’ in typically deep, pounding style in 2019. (“Good golly!” commented one fan online when it dropped and we can’t help but agree.)

Those early days were never more magical than when he was a resident at Heaven’s Soundshaft back in ‘89: even thirty years on, the memories make him smile and his eyes light up in delight. These were formative experiences that have never left him. “The club night was called Troll. And there was a club attached to it called Soundshaft, which was a smaller one. You could get into it through Heaven on a Saturday, through the little door and it was a mixed gay night. They used to have people going down there like Leigh Bowery. It was just an amazing short lived club. And it was so nice, it was a melting pot of different styles. There was a DJ called Steve Bell who looked a bit like Freddie Mercury but with blonde hair and the music was house and acid. And yeah, there''s some Italian stuff coming in! And it was a big range of stuff that was coming out and all that got played. And so you couldn''t really call it a techno club or a house club. And I think we all felt like misfits in society. And, and it felt good to be amongst those sort of people!” www.reprisetalentagency.comAfter this, Luke opened a store in Brighton called Jelly Jam. “But basically selling techno everything that I liked. So I''d go and pick up all the records from the distributors and bring it all back down to Brighton.” He started making records with a friend “and we did some records under a label called Jelly Jam. And that was linked to the studio and the actual distribution of it. And those first records were done in that studio with a lot of samples… but we did. We did one there called ‘The Pounder’. And suddenly in about ’91, the distributors were telling us that this record was massive in Germany.” But ultimately he wanted to be a solo (machine) operator. “I didn’t want to have to rely on anyone,” he shrugs. “That sounds like a massive insecurity but I guess that''s just the way and how I was formed. The idea of being able to do everything yourself and making everything yourself was a big drive.” Key albums followed like 1997’s ‘Freek Funk’, 1999’s ‘Wireless’ and 2002’s ‘Alright On Top’ with soul-flecked vocals from The Aloof’s UK frontman Ricky Barrow.

But in the early 2000s, global techno – even in Ibiza - got lost in a particularly gloopy soup called minimal. “And by 2007, I was getting a bit pissed off because minimum was very boring. And it wasn''t really my cup of tea. And I thought “you know what? I''ve got to get back in the saddle!” Because I''ve really got something to say and that''s the best thing! Have I got something to say? So I just started thinking about the right label to release something and I thought well, I''ll do it myself! You know, I''ve been with new NovaMute and all these labels in the past and I thought I’d start my own label, which is what happened in ‘94. I was thinking more about the live show, I was thinking more about the fact that the technology was there and I could play this music live, even going back to some of the ‘94 stuff. And I could represent it in a real way. So it became a serious thing in my head that I wanted Planetary to be a really special live show. With visuals, new technologies and ideas. And that''s what I worked on, a 3D screens show and I''ve done shows with the sax player and there''s been a few incarnations of ways to play live. That''s become a big, interesting topic for me: the idea of entertainment and how to represent things to an audience.”

And the phrase ‘better late than never’ was never more apt than in 2020, when Slater was finally bestowed with a two hour Essential Mix on BBC Radio One. “Yeah, that was a bit of a surprise! I mean, I always think it''s a win if someone has been supportive. I''m very thankful.” Is there anyone he’s surprised was a supporter? “That''s a good question. Well, surprisingly, I was actually surprised when Sven really supported my music. Because I remember when he was doing IQ Records and it was always very trancey! So I always felt we were kind of a million miles away. But over the years, we kind of got on a bit of a wavelength and that''s nice.” So Luke is happy with his lot. There’s plenty ahead. “Yeah, this feels to me like progress. When people love what I do, I''m just really thankful. It''s important for me to represent where I come from.”', 'https://www.awakenings.com/en/artists/luke-slater-planetary-assault-systems/900/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Rene Wise', 'rene wise', false, 'Rene Wise’s approach to writing music and DJing fuses together as one concept; tapping into primal human instinct via rhythm and groove.
Wise portrays a deep sense of knowledge and maturity in his sound, devising atmospheric soundscapes with a raw but modern touch, captivating the listener from beginning to end. His sets demonstrate this to full effect, consistently maintaining a powerful sonic trademark whilst possessing the innate ability to create hip-shaking poly-rhythms and multi-deck layers.
Before discovering the world of electronic music, Wise came from a background of drum and percussion which was guided by his Iranian father who was a professional drummer. This influence plays a huge part in shaping the foundation of techno that he crafts.
Wise’s ''quality over quantity’ mindset has seen him become a mainstay on influential labels such as Mote Evolver and Beard Man which has led him to work with some of the most respected names in the industry. His pure but passionate approach to music has given him the honour of gracing institutions such as Berghain and Fabric and earned him a residency at the esteemed underground Eerste Communie parties hailing from The Netherlands.', 'https://www.awakenings.com/en/artists/rene-wise/60110/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Fiene', 'fiene', false, 'Named fierce, dreamy and ruthless by 3 Voor 12, Fiene is one to watch. Surprising you with what you’ve never heard of, or reminding you of what you’ve always loved: Fiene seamlessly blends genres through oldschool sounds and new takes on the oldschool with influences from acid, trance, hardgroove and hardhouse. Effortlessly adapting to the vibe while sticking to what she loves most, Fiene’s sets flow with groove, feeling or simply raw energy.

Before playing at clubs and festivals, Fiene was no stranger to the scene. A strong desire tosee the artists she loved preform made her a familiar face on the dance floor ever since she was 15. With a deeply rooted passion for music that goes beyond genre or BPM, it’s no surprise she’s started producing her own tracks behinds the scenes.

You might have caught her playing at events like Intercell, Soenda, Thuishaven or By TheCreek. Haven’t had the pleasure yet? No worries, with events like Awakenings ADE, Teletech x Free Your Mind ADE and Into The Woods Festival coming up, there will be plenty of opportunities to see Fiene play in the near future', 'https://www.awakenings.com/en/artists/fiene/378542/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('EMILIJA', 'emilija', false, 'Step into EMILIJA’s electrifying universe—the Lithuanian-born powerhouse is steadily making her mark across borders, blazing through with her dynamic blend of raw hard house deep cuts to sultry techno and eurodance bangers, all laced with acid basslines and playful, tongue-in-cheek vocals. An unpredictable, boundary-breaking fusion of styles with tasteful curveballs to satisfy your nighttime cravings, best served hot: high-octane and hard-hitting yet still undeniably, skilfully sizzling. Nothing but pure fire as EMILIJA takes the reins— a wild ride you won’t forget.', 'https://www.awakenings.com/en/artists/emilija/382795/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Fenrick', 'fenrick', false, 'Fenrick is an emerging Belgian DJ and producer whose unique sound is shaped by a blend of influences, from UK garage and 90s trance to bouncy techno and hard house. Immersed in the electro scene from an early age, Fenrick''s music resonates with a rich diversity of styles, forming the foundation of his dynamic sets and tracks. Known for his evolving sound, he constantly pushes boundaries, creating experiential performances that go beyond the typical DJ set. Fenrick''s production journey has seen significant growth, with standout tracks like "MC Undertaker" and "Scotland Jus," as well as his EP "Before You Leave" on the Speed Master label. His releases have garnered strong support from renowned artists and a dedicated fanbase. With performances across Europe, Australia, Canada, and soon South America, Fenrick is quickly establishing himself as a force in the global music scene. Expect more surprises as he continues to shape his musical path.', 'https://www.awakenings.com/en/artists/fenrick/382798/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Noise Mafia', 'noise mafia', false, 'Noise Mafia is a DJ and Producer born in Bogotá, Colombia who has generated great notoriety in recent months. Inspired by various genres his initial goal has been to merge genres such as House, Disco, Trance and other sounds of yesteryear adapting them to new styles such as Hard Trance, Hard Dance and Hard Psy
and thus seeking to create challenging music.

Noise Mafia’s tracks are being played by great artists such as Sara Landry, Nico Moreno, Trym, Patrick Mason, Brutalismus 3000, and I Hate Models at events like Ultra Music Festival, Tomorrowland, Boiler Room, AMF Festival, Awakenings, Blackworks, EDC etc....', 'https://www.awakenings.com/en/artists/noise-mafia/368135/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Peterblue', 'peterblue', false, 'Electronic music is always evolving. People (the crowd) crave new sounds, mixes that move them both inside and out. The PETERBLUE project is based on disruption and innovation, always with Latin and danceable foundations, finding the perfect balance between the classic, fast-paced hard groove and the new wave of Latin club music. This has been widely embraced on dance floors across both America and Europe.

The pandemic led Peter to rediscover the origins of rave music and fall in love with its essence. This was when he rebuilt his artistic career, aligning it with his true passion: electronic music, all while staying true to his roots and essence.

Peter''s music quickly gained traction within various niches of the scene with tracks like "Bakalao" and "Fuego." In 2023, he released his debut EP Bailar Para No Pensar, which included classic tracks like God Save The Groove and Latin Ecstasy Club. With this release, he began taking his music worldwide. Later in 2023, he launched his record label PAS†I Records, a platform created for the artists he admires. In 2024, he released his third EP, Diskoteka Amerikana, through the label, which became a best-seller on Bandcamp shortly after its release. In October 2023, he embarked on his first European tour, covering several countries and earning rave reviews, particularly for his set at HOR Berlin, which was widely praised on social media.

Peter has always remained an independent artist but has had the pleasure of releasing music through labels like OBSCURE, Gomboc Records, and Muakk. He has garnered support from notable figures such as Hector Oaks, Adrian Mills (240km/h), Skin On Skin, Patrick Mason, Boyz Noize, Funk Tribu, OTTA, Antigone, David Löhlein, and Victoria De Angelis.', 'https://www.awakenings.com/en/artists/peterblue/382819/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Fumi', 'fumi', false, 'American-born, Berlin-based artist Fumi is emerging as a notable newcomer in the techno scene. Her eclectic taste in music blends bouncy, glossy tracks with sexy, energetic 240 elements. Taking inspiration from old-school hip hop, new wave hard groove, and curated techno, Fumi’s sound is not limited to any genre, but instead creates a new and unique sound through fast mixing and multi-deck building. Fumi aspires to attract diverse crowds, collaborate with other artists, and redefine the way we see and consume electronic music in an authentic and down-to-earth way. With a dedication to energy', 'https://www.awakenings.com/en/artists/fumi/362507/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('SPFDJ', 'spfdj', false, 'Not many DJs can claim to experience as meteoric, grassroots ascent as SPFDJ. Having established a remarkable energy, style and attitude on the underground techno circuits of both the London and Berlin circuits, she is known for inspiring debauchery and sweat-soaked hedonism on an international scale.

Typically operating at a blisteringly high-tempo, an SPFDJ trip takes no prisoners in it’s exploration of strains of techno, acid, EBM, hardcore and trance. It’s a style that Ben UFO called “utterly ruthless”, and one that more and more clubbers are submitting to; a gleefully chaotic two-fingers to dance music’s self-serious establishment.

In 2018, SPFDJ was inducted into the crew of residents at Herrensauna, the notorious monthly rave that has empowered and transformed Berlin’s queer scene in the past few years. Sharing a lineup with residents, this fertile and (not quite) fucks-free environment has seen SPFDJ’s sets become increasingly dynamic and uncompromisingly distinctive, a key tool in tipping the basement of Tresor over into trademark madness, as captured in an inspiring, increasingly iconic Boiler Room performance.

Owing to her access to techno’s bubbling, hardcore underground, SPFDJ established her label
‘Intrepid Skin’ in order to showcase the work of her contemporaries and those producing some
of the most challenging tracks in her set. So far, VTSS and Nene H have launched both vinyl
and digital music through Intrepid Skin, with further unruly transmissions soon to follow.
With a specific, uncompromising musical vision in mind, SPFDJ’s monthly residency on Rinse
FM further cements her ability to speak for the cutting edge of rave as well as revisiting the
genre’s vast archive; rediscovering, recontextualising and reintroducing some of the most
forward-thinking and irresistible electronic music ever made, her dedicated mixes have found
favour with both veterans of the genre and a fresh-blooded, thirsty generation of clubbers. Mixes
for i-D and Discwoman have further cemented her formidable reputation for mixing the sonically
impenetrable.

SPFDJ’s recent gig schedule has seen her appear regularly as a key feature of Berghain’s cutting-edge programming in the Säule venue, as well as internationally renowned clubs such as Bassiani in Tbilisi, Concrete in Paris, and Amsterdam’s De School. Deeper in the techno landscape, there were performances at Reaktor’s Unpolished, as well as an invitation to play alongside some of the scene’s heavyweights at the MMA closing party in Munich, and appearing at festivals including Dekmantel, Dimensions and No Bounds. She also continues to play with Universe of Tang, the all-female underground techno collective formed in London, whose wildly imaginative and creative parties saw SPFDJ cut her rave teeth, as well as on Berlin’s roving and formidable System.out Sound rig, gaining valuable insight into the raw technicalities of the rave, as well as the nous to handle huge records on an even bigger system.

In a scene of DJs determined to take their stand, precious few can match the impact of SPFDJ.', 'https://www.awakenings.com/en/artists/spfdj/57884/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Kobosil', 'kobosil', false, 'When you''re talking about Kobosil today, you''ll need to talk about life goals: to become an artist, to be an artist. Max Kobosil, born in 1991, grew up in Berlin in post-Wende times of structural change, he discovered Techno when it emerged from sub culture into modernity, from an early stage he was determined to contribute his share to the city and genre as well as coining both.

The initiation for everything that followed was marked by his first visit to Berghain. “At around 17 I was already spinning House and Techno and had heard one or two things about the club. When I turned 18 I went for the first time, after three hours of queuing up I finally got in. I realized very quickly: ‘That''s quite something – this club and the people inside make the difference. I''d like to be an artist here, not just a regular visitor.’ Eventually I met nd_baumecker and some other staff members and despite the age gap we were on the same wavelength immediately.“

The mutual understanding quickly led to his first releases: In 2013 Kobosil’s remix of Barker & Baumecker’s ‘Silo’ was published on Ostgut Ton, the same year saw Kobosil''s 12" debut on his own RK label as well as his EP - ----- on Unterton. With those records Kobosil not only left his mark in Berlin, but also built up a reputation outside of the city and country limits with his gusto for subtly hypnotic synth sounds, noise, ambient and especially the darker, more powerful variant form of Techno. Furthermore the 24-year-old proved himself as a versatile DJ since his Klubnacht debut in August 2013, skillfully combining new Techno records with genre classics, some acid, indie and industrial tracks, while adding pressure to his expressive and emotive sets at the same time.

Since day one Kobosil''s focus has been the balance between playing records and producing. “DJing very much lives in the here and now. With just one night you can define your own future, but a dj set comes to a halt at the end of the night. In contrast, the production side represents your own legacy. History has proven over and over that music needn''t have been a commercial success at the time of its release in order to grow as a cult record over the years. I see it as an artistic challenge to create something that can stand the test of time.“

The Neukölln resident has emphasised this aspiration in the past two years, be it with his club, ambient and live sets, with releases on Marcel Dettmann Records and his very own RK imprint, and via his recent, critically acclaimed remix of Terence Fixmer’s ‘Aktion Mekanik Theme’ on Ostgut Ton – all this exceeding his own visions. His latest release, the 91 EP (Ostgut Ton, 2015), once again proves his sense for functional techno with depth and drive; while his upcoming debut album extends his artistic range with all new moods and tones, ease and melodious sounds, without abandoning his familiar darkness. “I want next generations to perceive my album as music – not as techno music.“ It remains to be seen if Kobosil will meet his self-defined goals. His artistic signature and attitude is already distinctive.', 'https://www.awakenings.com/en/artists/kobosil/818/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Ornella', 'ornella', false, 'Ornella is a Portuguese DJ and producer making serious waves in the global hard techno and Schranz scene. Known for her relentless energy and different sound, her sets are a full-body experience — raw, hypnotic, and impossible to ignore.

Her productions speak just as loud, with tracks regularly charting in Beatport’s Top 100 and earning support from some of the scenes most respected names. As the founder of Ornella Invites, she’s built a bold platform in her home country while rapidly expanding her footprint with explosive debuts across Europe and the Americas.
She aims to turn every set into a powerful experience, driven by high energy, human connection, and a strong community spirit.', 'https://www.awakenings.com/en/artists/ornella/382813/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('DIØN', 'diøn', false, 'Once in a blue moon an artist emerges who does things to the dance floor that others can only dream of–a DJ who is the full package, a producer who makes you believe in dance music all over again.

Once in a blue moon, you get an artist like DIØN.

Eyes opened to the power of electronica during a transformational visit to Mysteryland Festival, DIØN is now one of the hottest properties in Hard Dance. In 2020 he dropped landmark single‘ Public Enemies ’via Autektone; by 2022 he made the decision to bring everything in house, setting up his Rough Material imprint. The label now stands as the only place to find his releases, including the four-track Rough Material EP, the Ketting collab ‘Make My P*ssy Rave’, the mammoth 2024‘Hard Rework’of‘Public Enemies’,and the hotly anticipated upcoming single ‘Moments That Matter’. The results undeniably match the hype; blending early 90s rave with synths, rough kicks and his signature drum sound, support has flooded in from the likes of Amelie Lens, Fatima Hajji and Sarah Landry, the latter also getting in the studio with DIØN, as has Oliver Heldens, and Funk Tribu. 

Outside of the studio, his shows have become the only place fans can hear his music live, creating an insane supply-and-demand issue. From his explosive breakout set at VERKNIPT2021 to his sold-out 2024 Rough Material showcase event at Amsterdam’s Paradis, DIØN has carved a fearsome reputation in both the DJ and the ticket booth. A certified headliner in theNetherlands and now increasingly overseas, DIØN’s tour diary is stacked, with an incredible150+ dates in 2023 alone including shows at elrow, Teletech, Rotterdam Rave, VERKNIPT, Spazio, Paaspop, Kompass, and Blackworks. As fans clamour to see DIØN, you’ll likely find them draped in some form of Rough Material clothing at his shows. 

With every label release comes a custom fashion line, each piece hand-designed by DIØN, testament to his polymath creative capabilities and part of his overreaching brand vision.With a huge arsenal of new music to release and a tour diary taking him into new territories worldwide, 2024 will prove itself the tipping point for DIØN, taking him from bright young thing to a guaranteed A-lister.', 'https://www.awakenings.com/en/artists/dion/368126/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Essy', 'essy', false, 'Groovy, funky, surprising, and versatile.
That’s the essence of an Essy set. Her selections are energetic, warm, and feel-good, ranging from 90s house to groove and everything in between.

She has been digging lots of progressive house and techno tracks, which are ready to be combined with breakbeat and electro. This year, Essy has been on a serious rise, lighting up stages at top-tier festivals. You may have seen her play at Wildeburg, DGTL, Intercell, Lowlands, 909 Festival, Thuishaven, or an ADE show, just to name a few.

Behind the scenes, she has been building her sound as a producer as well, aiming to reflect the variety of sounds she plays in her sets. So far, she has released her debut EP called Bouncin’ on Return To Forever and attributed her track “Get Up, Work That” to a summer-themed Foresight VA.', 'https://www.awakenings.com/en/artists/essy/384648/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Dr. G', 'dr. g', false, 'My aim as Dr. G is to create a sound that makes ppl feel happy, groovy and energetic, whilst immersing them in other cultural and musical era''s. In essence, giving ppl goosebumps is what I aim for! That''s why I inspire myself from the 90''s and 2000''s, to infuse my sound with a recognisable old school vibe. My track "Way of the Underground" is my magnus upom at the moment, and it reflects this sound perfectly; very groove, punchy and a 90''s Detroit House feel. I''m curently working on a lot of projects... so way more is coming up soon. On top of that I''ve already garnered support from big DJ''s in the trance scene like: Ollie Lishman, EMILIJA, WATTO, Test Press and way more!', 'https://www.awakenings.com/en/artists/dr-g/383005/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('BIIANCO', 'biianco', false, 'BIIANCO moves through the world like a mad scientist. The London-based, LA-built producer, DJ, pianist, bassist, drummer, vocalist, synth and modular aficionado is an engineer first and foremost; their mastery of the science and circuitry behind creating music is what continues to make them a once-in-a-generation type of artist. As a DJ, BIIANCO blends vocals and melody with harder sounds and faster speeds – leaning into their decades of experience with music theory and playing instruments to make advanced key and rhythmic mixing look effortless. BIIANCO exploded into dance music in 2023 after a live video of them performing their original song “Against The Wall,” (a collaboration with 1111 released on WUGD) went viral. 35 million views later, BIIANCO charted in over 20 countries, was named a Next Wave BBC Radio One Future Dance artist, and amassed an army of over 200,000 fans across socials around the world. With most of 2024 spent touring across Europe, the US, the UK and Australia, a new partnership with Ultra Records, and a collaboration with DJ Daddy Trance himself, Marlon Hoffstadt on Club Heartbroken, BIIANCO’s momentum shows no signs of slowing down.', 'https://www.awakenings.com/en/artists/biianco/382861/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('DJ Boring', 'dj boring', false, 'The origins of London based DJ & producer Tristan Hallis lie in Australia, where he was raised and cultured amongst some of the most interesting musical phenomena of the 21st century.

Watching DJ BORING in action is the antithesis of his mundane pseudonym; vibrant, energising, fun and full of passion, Tristan Hallis puts his all into every set. Over the last few years he has ascended rapidly thanks to his dazzling displays, impeccable selection and high quality productions. The Australian selector takes great pride in his digging capabilities, constantly searching for lesser-known gems from years gone by, and pairing them up with more recent cuts that are equally exceptional. 

Since he arrived with ‘Winona’ in 2016, DJ BORING has continued to push forward and demonstrate his abilities on stage, in the clubs, at festivals and behind-the-scenes in the studio. He has an innate ability to blend seemingly disparate styles. His debut on BBC Radio 1’s legendary Essential Mix and an amazing Boiler Room appearance at Lost Sundays exemplify this DJ style, but tune in to any of his streams, recorded sets or, better still, see him in person and you’re bound to be left buzzing by his sheer dynamism. 

In the studio, the producer has honed in on a contemporary sound that pays homage to the roots of dance music. His productions are birthed in hardware and imbued with Hallis'' energetic personality - a human touch which can often be lacking in many productions today. This trait shines through in his new live show where hardware and controllers become a natural extension of his creative self, a conduit through which he presents a fresh take on his music. 

DJ BORING epitomises the dance floor roots of club culture; positive energy, liberating and unifying selections and unbridled fun and self-expression, combined with respect for the music and a genuine desire to share his unwavering passion. Despite his impressive list of achievements it’s clear BORING is only just getting started, with his first live show finalised alongside plans for an album project in the not-too-distant future, the stage is set for the next phase of this soaring artist’s remarkable career.', 'https://www.awakenings.com/en/artists/dj-boring/382846/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Cybersex', 'cybersex', false, 'As Cybersex we are looking for the purest form of groove & rhythm. 

Many elements of dub, house and techno can be found around it, but not at the tempo you are used to. Cybersex plays at a fast pace so that most records are not even recognizable anymore. In addition, Cybersex has a soft spot for glitchy synthesisers, modulators and a sea of drum machines. 

One thing will always be central, the constant development of their sound and the search for groove & rhythm.', 'https://www.awakenings.com/en/artists/cybersex/198196/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Ellen Allien', 'ellen allien', false, 'As one of the most iconic artists of her generation, Ellen Allien embodies the core ethos of techno: a visionary who looks to the future for inspiration, carving out her own niche and presiding over an empire that has imbued techno, and dance music culture, with her unique DNA. Her latest LP, AurAA, dropped in June 2020 featured a variety of hard-hitting, rave-inspired techno cuts, but all delivered with Ellen’s idiosyncratic sound signature; high-octane beats and distinct use of vocals with irresistible rhythms and grooves, which create listening and emotional qualities that resonate beyond the dancefloor. Unable to tour in 2020, she conceived the Balcony Streaming sessions, hosted from her home in Berlin. The livestreams allowed her to continue DJing and engaging with her fanbase, while also supporting music from a wide range of artists, new and old.

She channeled her curatorial experience into an expansive three-part compilation series. Named after her We Are Not Alone parties, the collection comprised 33 tracks from artists that embody the ethos of the brand; club music with a rugged aesthetic and an unapologetic dance floor focus. Her most recent releases are tracks on compilations by the collectives Gegen Berlin and Serendeepity. Before the end of 2021 she''ll release the remixes of one of her favorite bands Lebanon Hanover on BPitch - originally created for her own sets and released by popular demand - a new EP for her label UFO Inc, and a remix for Regal.', 'https://www.awakenings.com/en/artists/ellen-allien/450/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Morgan', 'morgan', false, 'Morgan, an experienced DJ and producer with 15-years behind the decks. Originally from Sydney, Australia her nomadic spirit led her to spend time in Barcelona and Bucharest until finding her place in the city that never sleeps, New York City.

For the past 5 years, Morgan has been the esteemed resident DJ at Golden Record NYC, sharing the stage with iconic figures like Ron Trent, Mike Huckaby, and Detroit In Effect, to name a few.

Her residency has served as a launching pad for a dynamic career that has taken her across the globe. From NYC''s Resolute to Amsterdam''s Slapfunk & VBX as well as notable festivals such as Waking Life, Sunwaves, and Garbaciz, Morgan has left an unforgettable mark on each stage.

Her musical prowess shines through in her ability to seamlessly navigate diverse sets, effortlessly transitioning between deep and flowy to highenergy performances. Drawing inspiration from her early days as a Hip Hop DJ, she has cultivated a distinctive style that spans across various genres of house music and other percussive, rhythmic styles. 

Her unwavering dedication to the craft makes her a force to be reckoned with in the ever-evolving landscape of electronic music.', 'https://www.awakenings.com/en/artists/morgan/294037/')
