  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Ryan Elliott', 'ryan elliott', false, 'Ryan Elliott''s early days included legendary residencies at Ann Arbor’s Goodnight Gracies and Detroit’s Shelter, which soon gave way to a rigorous international travel schedule. He began working for crowds at clubs and festivals around the world, from NYC’s Guggenheim Museum to Barcelona’s Sonar by Night, and tailoring his approach to each show with a meticulous ear and a bottomless record collection. Influenced by his hometown staples (Axis, Purpose Maker, M Plant, and UR) along with international labels like Perlon, Playhouse, and early Kompakt, Ryan inhabits his kick drums, becoming an extension of the music and vice versa.

 2009 saw Elliott relocating to Berlin to further his focus on DJing, production, and helming Spectral Sound’s growing roster from a new international perspective. “Berlin and Detroit may not look the same, but they feel the same" he says. "The connection isn''t just in the music, but also in both city''s rough edges and honest hearts."

 Ryan Elliot''s sound remains unchanged: bassline-driven techno and house reduced to their essence, thoughtfully calibrated to drive crowds out of their minds. The time is right, the tracks are right, and Ryan Elliott is exactly where he needs to be.', 'https://www.awakenings.com/en/artists/ryan-elliott/1346/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
