  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Prance', 'prance', false, 'One of the most recognizable faces from the vibrant Amsterdam scene. After years of gracing the Amsterdam dancefloors and carefully studying the great selectors our scene has to offer, Prance has finally made the transition to the DJ booth.

With a vast range of influences from the musical roots of his motherland, the platform for culture & fashion he facilitates with TGIB, and the 1000’s of hours spent on the dancefloor; Prance his performances are always set to surprise you.

Connecting is the key here and if there’s somebody who knows how to do just that, it’s Prance.', 'https://www.awakenings.com/en/artists/prance/382807/')
