  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Dold', 'dold', false, 'Stockholm repper Patrik Eriksson is a proponent of loopy and emotionally charged techno, with one eye sharply focused on its truest forms. Under his Dold moniker, the DJ and producer crafts moments designed for both home and club, resonating with evocative simplicity.

Since founding Arsenik Records in 2015, he has built a vital platform for techno on his own terms, steadily expanding its catalogue and showcasing the work of like-minded artists. This path has led to releases on some of the most respected labels around, including KEY, Token, Fuse, and Bassiani, as well as performances worldwide.

Positioned at the forefront of the European techno scene, Dold combines his timeless machine music across a wide range of sub-genres. While the linear thrust of 4/4 techno forms the backbone of his sound, his recorded work and live sets equally encompass ambient, IDM, breakbeat, and electro, but never fail to deliver consistency with inviting character and charm. Stripped-back yet deeply expressive, Dold’s music channels techno’s history while steadily charting a path forward.', 'https://www.awakenings.com/en/artists/dold/382833/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Ogazón', 'ogazón', false, 'The part-Spanish, part-Luxembourgish artist has cultivated her skill and selection process in Amsterdam’s after-hourscene. Now residing in Berlin, her rhythms find inspiration in the eclectic and somewhat wilder characteristics of the city. Not bound to a sound in particular, Ogazón is best in arranging a coherent thread of feelings throughout her sets, be it melancholic bliss, ecstatic hope or just pure dance floor pleasure.', 'https://www.awakenings.com/en/artists/ogazón/214760/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Chontane', 'chontane', false, 'A Berlin-native with Ukrainian roots, Chontane has been carefully shaping his sonic aesthetic for several years. It’s his dedication on all levels and professions with sound that has fueled his rise in the international scene through consistent releases and gigs at Basement in New York, RSO and Tresor in Berlin, Bret and Radion in Amsterdam, Fold in London, Fuse in Brussels, or even Laster in Madrid. The young selector has passed through Europe’s most respected booths to play his percussive blends to motivated dancers. 

Whether it be in his regular DJ setup or his new vinyl/digital hybrid, Chontane’s sets maximize grain and transients while staying efficient and fresh all the same. As a producer, the impact of his records come from his long standing interest with the music, but also from his background and experience as a sound engineer. His work stands at a stylistic crossroads between various dance genres, easily slipping into just about anyone’s tracklist. His tracks have found homes on Mutual Rytm, Dax J’s Monnom Black, Remco Beekwilder’s EMERALD, ARTS, and Illegal Alien, as well as his own imprint TANE, where many more records will be released on a regular basis. Ready to push boundaries and surprise music enthusiasts wit unexpected blends to fire off his erratic taste in music, Chontane’s mixes and productions represent today’s necessity for the perfect balance between consistent innovation and guaranteed efficiency.', 'https://www.awakenings.com/en/artists/chontane/382836/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
