  VALUES ('Vil', 'vil', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('TWIENA', 'twiena', false, 'While she was raised with a fusion between western values and traditional Asian culture, it took Twiena several years to develop her own ideas of what life was really about and discover the courage to go after her passions with full force.

From the dynamics of Twiena’s low-end grooves, to the fluidity of her music as she introduces a balance between her pure love of 4x4 Rave & Techno sound, raw 90s aesthetics, uplifting melodies, and perceptive mixes of emotion & intensity all fused into unforgettable moments in time. With an uncanny ear for sound, Twiena supplies her audience with high-energy vibes that blend & blur the lines between authentic Techno, Ghetto, contemporary Trance, pure Acid textures, and influence from the roots of electronic scene from the UK, all the way to Chicago – Twiena creates unparalleled combinations of rump shakin’ rave tunes designed to redefine the nightlife.', 'https://www.awakenings.com/en/artists/twiena/296030/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Beste Hira', 'beste hira', false, 'Beste Hira is an adventurous, strong-willed and motivated DJ and Producer living in Amsterdam, originally from Istanbul. Her character traits, combined with her creativity and discipline, define her as a unique talent. Music has been a huge priority her whole life: she focused her entire high school and university path on it, most specifically with the cello and piano as her main instruments. She graduated from Ondokuz Mayıs University with a degree in Music Education / Conservatory. During the early days of her career, she started producing and DJing in Istanbul before she decided to move to Amsterdam in 2019 to pursue her vocation as a techno talent.

Within electronic music, Beste Hira identifies with the hypnotic, fast paced and dark side of techno. Her extensive musical training can be heard throughout her music production and DJ sets, where sh meticulously experiments with sounds to produce her signature, and, most importantly, having an incredibly accurate intuition allows her to play out of her comfort zone and surprise some of the most challenging crowds.

Beste Hira enjoys creating a full sensory experience in her performances, which results in captivating journeys from beginning to end. Her knowledge and experience as an artist have allowed her to grow in Amsterdam''s eclectic underground scene, supported by key Amsterdam-based crews such as Orphic (who invited her to become a resident at their events series), DeSchool and the famous Vault Sessions, as well as playing at the Netherland''s most renowned festivals, such as Awakenings, Amsterdam Dance Event, Amsterdam Open Air and the upcoming The Third Room, to name a few. Beste''s presence in Europe is growing rapidly, especially after playing several times at the mighty Berghain and other top notch clubs in capitals like Vienna, Madrid and Paris.

Creating podcasts for communities based in Miami, Mexico, the UK, Europe and Turkey has allowed Beste''s voice to reach global audiences and has continually shaped her growth as an artist.

Cos, the first EP she released on her own, allowed her to break through the scene and opened doors for her debut at the renowned underground Schimmer Records. She''s got a lot more coming up, including projects that integrate her classical background, like her upcoming collaboration with Ignez and more TBA', 'https://www.awakenings.com/en/artists/beste-hira/197817/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Lobster', 'lobster', false, 'Dutch DJ and producer Lobster is another example of Amsterdam’s visionary and fertile underground scene. Emerging from the notorious rave community through his former residency at Orphic Amsterdam, where he perfected the craft of playing dance floor and storyline inspired techno, this current Vault Sessions resident knows how to adapt to any crowd. 

Combined with his unconditional passion for electronic music, it is certain Lobster is a force to be reckoned with. With a musical library spanning multiple sub-genres, tempos, and decades, Lobster always has the fitting track ready to be played out, scouting the dance floor for the perfect moment. His strong work ethic and keen sense of the crowd have led him to play sets for hungry audiences in venues all across the globe, like a 12-hours closing set at Bassiani, Awakenings, Freedom Medellin, Reaktor, Basement New York, Gotec and many more. 

After focusing on playing music rather than producing it himself, he started to write his own music in his studio since a few years. He focusses on hypnotising, trippy techno which is very in line with the sound he pushes as a DJ. Until now he has successfully released his stellar creations on solid labels like Room Trax, Format, Warok and Oecus.', 'https://www.awakenings.com/en/artists/lobster/199697/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('ANNĒ', 'annē', false, 'Born and raised in Thessaloniki, Greece, Annē began her music career in 2012 and has since emerged as a rising talent in the world of techno. Fully committed to her craft as both a DJ and producer, she transitioned from being a passionate raver to a driving force in her country’s techno scene, delivering a uniquely experiential approach to music.

Annē’s DJ sets are high-energy and dynamic, crafted to create seamless connections with her audience. In her productions, she draws inspiration from Detroit techno and the sounds of the ’90s and early 00s, channeling her emotions into tracks that resonate deeply. Annē’s talent has taken her to some of the world’s most iconic clubs and events, including Berghain, Bassiani, RSO Berlin, Radion, Fuse, Fold, E1, Exhale etc. She has toured extensively across continents, performing in South America, Africa, Australia,Asia and beyond. With exciting collaborations and multiple vinyl releases planned for the near future, her trajectory continues to ascend.

Her latest record on FJAAK''s label, CROWD/SPANDAU20, is making waves on dance floors, marking a significant step forward in her career. Many more releases and new collaborations are coming in the near future. For Annē, the DJ’s role is deeply intertwined with the audience. She believes the dancer is an integral part of the musical experience, with both performer and listener contributing equally to the atmosphere. This philosophy keeps her grounded—one foot always on the dance floor, the other in the booth.', 'https://www.awakenings.com/en/artists/anne/361588/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Ben Sims', 'ben sims', false, 'Skip forward over 15 years and you’ll find he’s one of the UK’s biggest techno exports and a much in demand producer. Ben has been involved in running 9 labels, a couple of which are on hold at present (Theory, Killabite, Hardgroove, Native, Ingoma, Symbolism, Assembly, KB Records inc, Split Music), each one with a distinctive sound, ranging from hardgroovin’ and funk driven techno and house that is the trademark of his DJ sets, via tribal, to melodic electronica. In a genre that propagates sound-a-likes, Ben Sims productions have gained widespread attention and feature regularly in the boxes of his own personal heroes like Derrick May, Kevin Saunderson, Jeff Mills and Rolando, whilst also attracting crossover appeal from the likes of Carl Cox etc. He has remixed Jeff Mills, Green Velvet, Blake Baxter, DJ Funk, Marco Bailey, Chris Liebing, Adam Beyer plus many more and has had his tracks and remixes featured on mix cds by Robert Hood, Francois Kevorkian, DJ Rush, Joey Beltram, Dave Clarke, Umek, Luke Slater, Sven Vath, Richie Hawtin and hundreds more. The past 10 years have seen Ben constantly touring and tearing up dancefloors at legendary clubs & parties like- Liquid room, Tokyo, Sonar, Barcelona, Limelight. NYC, Rex, Paris, Zouk, Singapore, I love Techno, Gent, Tresor, Berlin, Awakenings, Amsterdam and Atomic Jam, Birmingham plus hundreds of others with his tight, energetic and skilful brand of 3 deck wizardry. Add this to the 6 deck ROKU sets with Mark Broom, recent ventures into promoting with both the Retro_vert and Split parties causing a storm in London, a monthly internet radio show presented with Alex Downey and a new mix cd lined up for the Slovenian based Matrix series, plus the FREQUENCY 7 dex ́n ́ fx and laptop shows with Birmingham''s Surgeon, pushing the boundaries of DJ sets or as part of the ESSEX RASCALS with Tony Anderson, Mark Broom and Paul Mac dropping everything from House to Funk to Disco. The illusive classics remixing duo KILLA PRODUCTIONS again with Paul Mac, plans for a disco re- edit project and after recent bizarre but genius use of the hit ''Remanipulated'' in a hardcore lesbian porn clip doing the rounds on the net, you can certainly expect some sexy new beats from Mr Sims very soon!', 'https://www.awakenings.com/en/artists/ben-sims/150/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Anetha', 'anetha', false, 'Transmitting the glossy textures of techno, trance and experimental music, Anetha whips up bouncy bass lines, stomping kick drums, glorious melodies and a sprinkling of melancholic motifs, gracing clubs and festivals worldwide. Since breaking out on the Parisian scene in 2012, the Bordeaux-based artist has garnered a global audience, delivering lush and luminous sounds with attention to detail, nimble mixing and absolute focus — as one would expect from an artist with an architectural background.

2024 marks the release of Anetha’s album on Mama told ya, welding a palette of post-club, techno, nu-wave, rave, and DnB and exploring themes of sustainability, femininity, toxic masculinity and unwarranted opinions in the music industry. In true Anetha style, she conveys these subjects with playfulness and a touch of irony.

Several releases colour Anetha’s discography, from her debut EP ‘Ophiuchus’ on Work Them in 2015 to music on her own label, Mama told ya. Launched in 2019, the label platforms rising stars through its catalogue and showcases worldwide.

On Anetha’s new label Fané.e, every release follows a seasonal schedule, where tracks will be available to download and stream fora finite period until blossoming once more the following season. The label aims to share genre-fluid productions without the restrictions of a vinyl-led imprint and to cultivate a more environmentally friendly way to consume music.

In 2020, Anetha launched the talent agency Mama loves ya to sustainably nurture emerging artists. Actions include implementing eco-riders and publishing an open calendar, helping promoters minimise travel distance between bookings. MLY also works withGreenly to help offset, reduce, and compensate for the agency’s carbon footprint.

Born in Bordeaux to nu-wave and electro clash-inclined parents, Anetha later moved to London and then Paris, where she graduated in architecture. There, she co-founded the Blocaus label and party series, honing her skills as a DJ and producer.A decade later, Anetha is a fully established artist, blurring the lines between art, music, and fashion through her artistry and relationships with designers Marine Serre and Rombaut. If anyone can do it all with poise, it’s Anetha.', 'https://www.awakenings.com/en/artists/anetha/51400/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Pegassi', 'pegassi', false, 'Pegassi is the creative alter ego of Sam Huybrecht, an electronic music producer from Belgium, whose genre-defying sound is pushing the boundaries of eurodance, trance, techno and house. Pegassi’s journey to the forefront of the electronic music scene began with his remix of ‘No Type’, which shot to #1 on Soundcloud’s global charts, marking the start of a rapid rise.His breakout club anthem ‘Yoyoyo’ continues to ignite dance floors worldwide, becoming a favorite among many of the scene’s top artists. Pegassi’s bold, energetic productions, spanning a wide array of genres, have garnered support from key tastemakers likeMarlon Hoffstadt, Anetha, Trym, Bad Boombox, Malugi, Job Jobse, VTSS, Solomun, and many more. Recently, Pegassi collaborated with DJIP on the well-received track ‘Wanna Feel’, and fans eagerly await his highly anticipated release ‘No Go Zone’, featuringDutch hip-hop icon Bokoesam. Pegassi has performed at some of Europe’s most iconic venues and festivals, including Thuishaven, Mondo Disko, Junkyard, RSO, Tomorrowland, Else,Intercell, Modul’air, BCCO, Teletech, and a memorable Boiler Room broadcast that has garnered widespread attention.Beyond his success as a performer, Pegassi has launched his own event series and label, Sweet Nothing, through which he plans to tour the world while releasing music from up-and-coming talents. With major projects on the horizon and his unique ability to blend genres, Pegassi is poised to leave an indelible mark on the global electronic music landscape.', 'https://www.awakenings.com/en/artists/pegassi/367230/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Ben UFO', 'ben ufo', false, 'The rise of the Hessle Audio label has been well documented with in depth feature pieces appearing, along side guest mixes, on Resident Advisor and to a lesser extent FACT magazine. But reading ‘words’ about the strains of percussion fused dubstep the collective have released serves little justice for the wealth and extensiveness of the catalogue they’ve accumulated. To get a real feel for their output you have to listen to the music super loud, in a dark room, surrounded by bodies swaying rhythmically with the occasional enthusiastic whoop screaming out of somewhere in the void of bodies behind you.

Guided by Ramadanman, Pangaea and Ben UFO the collective formed up in Leeds (although none of them still reside there) and have so far released 16 records.', 'https://www.awakenings.com/en/artists/ben-ufo/152/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Four Tet', 'four tet', false, 'Four Tet is the electronic outlet for the solo work of Kieran Hebden. Four Tet is the electronic outlet for the solo work of Keiran Hebden. First single was the 36-minute ‘Thirtysixtwentyfive’ on Trevor Jackson''s Output Recordings label (1998). ‘Dialogue’ was Four Tet''s first full-length album, fusing hip-hop drum lines with dissonant jazz samples. 

In 2001, Four Tet''s second album ‘Pause’ was released on Domino and found Hebden using more folk and electronic samples, which was quickly dubbed "folktronica", while “Rounds”, Hebden''s most ambitious album to date, was released in May 2003.

In March and April of 2005, Four Tet performed two shows of improvisational music, in collaboration with jazz drummer Steve Reid, in Paris and London. He also appears on Steve Reid Ensemble 2005 album Spirit Walk. This collaboration was extended into a series of international tours, and the release of two albums, The Exchange Session Vol. 1 and The Exchange Session Vol. 2 over the course of 2005 and 2006. 

Hebden has also remixed artists including Madvillain, Bloc Party, Super Furry Animals, Beth Orton, Badly Drawn Boy, The Notwist, Boom Bip, Kings of Convenience and Radiohead.', 'https://www.awakenings.com/en/artists/four-tet/323251/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Nina Kraviz', 'nina kraviz', false, 'The internationally renowned Siberian electronic music artist Nina Kraviz is the most successful woman in her field: headliner of the world''s largest music festivals, acclaimed producer, singer and the founder of two record labels трип (trip) and Galaxiid. 
Famous for an eponymous artist album and two critically acclaimed DJ mixes for fabric and DJ Kicks, Nina has become one of the foremost curators of electronic music today. In 2017 she was declared ‘DJ of the Year’ by Mixmag, cementing her status within the global music community. Nina reaches wider, deeper and further back in search of cosmic and inspirational sounds: she performs at the world’s most unusual locations including the Eiffel Tower and Great Wall of China, the biggest festival stages and tears up underground club parties. 
In the studio she lets her productions evolve without constraints, resulting in a varied yet coherent discography.
On the one hand, "tarde", "this time" or "skyscrapers" show an unexpected yet fresh crossover side of herself. On the other hand, "hace ejercicios" or "all his decisions" are club tracks proving she is always ahead of the curve.
Nina''s authentic, creative and strong personality, her unique music style and constant pursuit of deeper feeling, make her one of the most outstanding music talents around the world.', 'https://www.awakenings.com/en/artists/nina-kraviz/1078/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Remma', 'remma', false, 'Organizing raves from a young age and establishing the DIY station, ITMOTR Radio, which has played a significant role in shaping the music culture of the outer Eastern corner of the Netherlands. Heavily influenced by the deeper side of house/techno and the free party movement of his own region, Remma is on a quest for an in-depth club experience where rhythm, beat and story come together.', 'https://www.awakenings.com/en/artists/remma/382980/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Thoms Traxx', 'thoms traxx', false, 'With a meticulous vision and fierce determination, Thoms Traxx is an artist moving at the pinnacle of the Dutch techno scene. His intelligent and resourceful approach to his craft gained him a well-respected name in his city of birth, Amsterdam, where he played at places like De School, Radion, Awakenings, and RAUM. Over the course of the years, he became a critical figure of the ORPHIC rave organisation, curating events and fostering a close-tied community at the forefront of the city''s underground movement. Both as an artist and a personality, he has been captivating dancers, bookers, and music professionals across both established and new generations. Moved by curiosity and vigour, Thoms Traxx is an ever-evolving force that can’t be missed out on.', 'https://www.awakenings.com/en/artists/thoms-traxx/199707/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Cio D’Or', 'cio d’or', false, 'Cio D’Or is a project-orientaed sound artist, composer and DJ. She is deeply immersed in her creative process: developing sound, preparing performances, and composing piano pieces. Her projects are cohesive entities - with tracks serving as crafted fragments of the dramaturgy she shapes in her studio and she bridging the worlds of techno, art, and composition.

Her music balances architectural precision with fluid, cinematic immersion. Every element is placed with intention, shaped by an acute awareness of structure and space, and refined over decades of aural sensitivity. Drawing from jazz, classical music, and contemporary dance, her sound is informed by timeless influences like Bartók, Stravinsky, and Bach.

A dedicated DJ since the late 1990s, her sets are built with a strong sense of dramaturgy - selecting and sequencing tracks to reveal subtle, hidden connections. She began producing out of necessity, starting with an MPC 2000 and a microphone on the shores of the Sinai Desert. Her expansive output includes two films, three albums, 14 EPs, musical theatre productions, collaborations and several renowned scholarships.', 'https://www.awakenings.com/en/artists/cio-dor/382971/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Claudio PRC', 'claudio prc', false, 'Creating sonic bridges from the literal, perceivable world into mythical, imaginal realms is what
Sardinian-born and Berlin-based DJ and Producer Claudio PRC might be best known for.
Instead of using extravertive elements, he enhances the overall experience through a wide-
screen appeal, playing with spatial awareness through details and taking the audience on a
journey into the all-or-nothing of sound. So far Claudio PRC has released on Prologue Music,
Semantica Records and most recently Delsin Records. He is the founder of 012, a label and
curated night held in several places across Europe, where he focuses on collaborative work with
connected producers and visual artists. Like in everything he does, a Claudio PRC DJ set is a
meticulously sewn journey. This makes him a key protagonist in the emerging world of hypnotic
techno, playing regularly at an international level at the most reputable festivals and clubs.
Resident DJ at Prague’s Ankali, from 2023 on Claudio PRC is holding a residency at Berlin’s
long-standing Techno institution Tresor.', 'https://www.awakenings.com/en/artists/claudio-prc/213742/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Abstract Division', 'abstract division', false, 'Dutch duo Abstract Division is out on a mission. With over 25 years of collective experience under their belt, Paul Boex and Dave Miller are skilled selectors who go above and beyond to find the right record for the right moment. Releasing on their own Dynamic Reflection label, the pair imbue their cuts with hypnotising drones and expansive sonic soundscapes that manage to be physical yet uplifting. After more than twenty years in the game, they are as able in the booth as they are in the studio and it means they can react to, and rock, any given club or festival.When not touring the world, the pair host their own Decode parties at Transport in Rotterdam, a proper techno experience and often the testing ground for their own essential tracks. The signature sound captured in their productions, always find their way into the record bags of the world’s key DJs, and each new release marks a subtle evolution in sound. Never sitting still, Abstract Division is a true techno force.', 'https://www.awakenings.com/en/artists/abstract-division/16/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('JakoJako', 'jakojako', false, 'Primarily a live performer, JakoJako makes extensive use of modular synthesis in her productions and on stage. ”Depending on how you configure your system, you can design a completely different instrument every time. I love when it’s surprising me.” When not in the studio, her expertise is put to use advising well-established artists on their own systems at Berlin’s synth-mecca SchneidersLaden.', 'https://www.awakenings.com/en/artists/jakojako/199166/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('LSD', 'lsd', true)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Luke Slater', 'luke slater', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Steve Bicknell', 'steve bicknell', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective)
  VALUES ('Function', 'function', false)
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Ignez', 'ignez', false, 'By not taking usual paths and knowing his inner self, it all felt natural for Ignez to devote more of his life to electronic music. His roots are in between dust of sand and waves of salt water. Ignez grew up near the coast of The Netherlands where hypnotizing waves and infinitive dunes shaped his sound. He fled the conservative world by sketching his own reality with these elements of nature. This became inextricably linked within his consciousness and reflects back into his music today, bringing a tight yet indefinable techno sound.

He has shaped his own path through his imprint, Somov Records, where he unveiled his distinctive sound and artistic vision for the first time. In addition to his own imprint, he has made an indelible impact on influential labels such as Token and SK_eleven, enchanting audiences worldwide with mesmerizing releases. Notably, Ignez has collaborated with Rødhåd. Together, they have created two EPs that showcase their unique musical synergy. 

In his DJ sets, Ignez transports the audience into a mesmerizing sonic journey, captivating their senses and lifting the dance floor to a higher state of being and a collective oceanic feeling. His driving, hypnotic, and minimalistic approach pulls listeners into a magnetic trance, where the pulsating rhythms and ethereal melodies create an immersive sonic experience. His residency at the esteemed underground Eerste Communie has been the cornerstone of his development as a DJ, fostering experience that has grown with him from a young age.

From intimate club settings to renowned festivals, his sets evoke a transformative experience, inviting listeners to embark on a sonic odyssey and dive into the depths of his sonic universe.', 'https://www.awakenings.com/en/artists/ignez/214511/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Rødhåd', 'rødhåd', false, 'Rødhåd has been socialized by Berlin’s looptechno nights and always finds the perfect balance of timeless techno to lift the dancefloor higher and higher. His style is always deep, powerful and melancholic – from dub to techno and back to house. Now an established force in contemporary Techno, Mike Bierbach, better known under his stage name Rødhåd is someone who has seriously put in the work. Having cut his teeth Djing as a relatively unnoted (but well loved by those in the know) local in Berlin for 10 years, one could argue that by the time success knocked on his door, he was more than ready for playing the international stage. It was during these 10 years of obscurity when he refined his craft to become the singular DJ he is now. Launching his party-series-turned-label Dystopian in 2009 was what truly tipped the ball over for Rødhåd. In a time where the Berlin scene was heavily oversaturated by fluffy, miscellaneous dance music, he & his peers set out to form a platform for real techno. The reception to this was raucous. Although he has lauded productions and remixes to his name, DJing is his true forte. Before abandoning his day job as a draftsman in construction “The Red” (as some call him due to his gingered, bearded appearance) was known for playing very long sets in Berlin’s most notorious hideaways. With an album, several EPs & remixes for a multitude of different artists under his belt, Rødhåd the producer has received equal praise as Rødhåd the DJ. Dystopian has hosted most of his releases, but in 2018 he founded a new label WSNWG that serves as a home for collaborative productions, excavated in sessions at his East-Berlin studio with his peers such as Rene Wise, Lucy, Lady Starlight, Fadi Mohem, Alex.Do, & Antigone.', 'https://www.awakenings.com/en/artists/rodhad/1352/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Freddy K', 'freddy k', false, 'Freddy K: techno activist. Since the ‘90s Alessio Armeni has been tireless campaigning from the dancefloor, defending vinyl, championing young talents and reinforcing the scene from the shadows. You will know him best for his marathon DJ sets and deviant selections. You might recognise him as the head of KEY Vinyl, or for the backstage role he played at M_Rec, the label he helped run with best friend Max_M. You should definitely know about Virus, the thing that started it all off for him back in Rome.
Lory D and Leo Anibaldi’s The Sound of Rome movement; Luca Cucchetti’s renowned Mad radio shows; warehouses, soundsystems and rave all informed Freddy K’s earliest obsession with techno. He started DJing at Sunday after hour events, having danced all through the night himself. In 1993, aged 21, he launched his now famous Virus radio show, which ran daily from 8PM to midnight, and from midnight to 6AM every Saturday. Parties, a booking agency and record shop soon followed: the Virus movement had arrived. A year later Freddy K signed to the legendary ACV, who released his first EP, Control. Rage Of Age, his debut album came in 1995; a dark and noisy record influenced by his two passions, Chicago acid and rock. It was widely lauded throughout the country and remains a testament to the old Sound of Rome today.
After Virus peaked and having toured all over the world with ACV, Freddy K stopped DJing and retreated to the backroom. He spent the early millennial years working with Sandro Nasonte at Rome’s flagship record store, Remix. Together they set up the influential Elettronica Romana label, which released some of Donato Dozzy and Giorgio Gigli''s first EPs. In 2005 Freddy K launched K1971, a label management enterprise that continues to support fledgling initiatives today from its base in Berlin. He moved to the German capital in 2009, setting up KEY Vinyl as a “techno label for DJs” two years later. Artists like PVS and Héctor Oaks have helped forge the label’s (and Freddy K’s own) traditionalist view on techno.
Moving to Berlin reignited Freddy K’s teenage infatuation with rave. He soon fell in with Homopatik, the former monthly gay event at ://about blank. He became notorious for his epic 10, 14 and 16 hour-long sessions there, playing always strictly vinyl and in a dynamic, party conscious fashion. Freddy K sets are characteristically mercurial and 100% tailored for the dance. He plays a “360°-style of techno,” which can include Soft Cell, WestBam or Bronski Beat—when the timing is just right. He played his first Berghain set in 2013; two years later he was closing the place, keeping the energy levels soaring well into Monday. The last 20 minutes, he says, are the most important. So be sure to stick around till the very end.', 'https://www.awakenings.com/en/artists/freddy-k/214347/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Marrøn', 'marrøn', false, 'Continuously trying to exceed his own limits, MARRØN employs fast rhythmics inspired by his roots. The artist’s moniker pays homage to the strong-willed MARRØN''s, a once-enslaved African tribe who defied oppression and found freedom in the primeval forests of Surinam. The hypnotic, percussive beats characterizing MARRØN’s foundational Afro Deep style have evolved to form a singular conception of techno. His dynamic take on the genre is at home in the underground, most notably in his role as co-founder and resident of Amsterdam’s EERSTE COMMUNIE. MARRØN’s capable command of groove, power, and texture is no doubt a convincing invitation to stay on the dancefloor for hours.', 'https://www.awakenings.com/en/artists/marrøn/57517/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Alycia Bezgo', 'alycia bezgo', false, 'Alycia Bezgo is an emerging talent in the electronic music scene at 27 years old, known for her passion and innovative approach. Based in Gent, she skillfully blends the driving rhythms of hard groove, techno, and trance to create engaging performances that resonate with audiences.

Her musical journey began in childhood, influenced by her father, a former DJ. This early exposure sparked her interest in music, leading her to explore various genres and develop her unique style. Since 2023, she has actively refined her mixing skills and embraced opportunities to grow as an artist.

Alycia’s sets are characterized by groovy vibes and a dreamy atmosphere. Drawing inspiration from the nostalgic sounds of the ''90s, she incorporates familiar elements that connect with listeners.

With a talent for intertwining danceable beats, Alycia creates an energetic environment that appeals to both new and seasoned fans. She has performed at notable venues such as Pukkelpop, Decadance, Club Vaag, and Rampage. Each performance demonstrates her ability to read the crowd and tailor her sets for maximum impact.', 'https://www.awakenings.com/en/artists/alycia-bezgo/384406/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Faster Horses', 'faster horses', false, 'Few artists have risen through the ranks of UK Dance Music as quickly as Liverpool born, Manchester based Joe Germains, aka Faster Horses. Jumping into the scene as a fresh-faced 18 year old back in 2020, they quickly made a name for themselves pushing a unique brand of trance-tinged techno, drawing inspiration from the vibrant dancefloor culture of cities like Copenhagen and Berlin. This led to a slew of international debuts across the continent before he had even stepped foot in the booth of a UK club. 

Making the move to Manchester in 2021, Joe began to pull inspiration from his new home, cutting his teeth in the sweaty, packed out basements of Fallowfield, along with institutions such as The White Hotel, Hidden and The Warehouse Project. Quickly developing a love for the music the north had to offer, Joe found himself developing a broad range of tastes, from UK techno to Jungle, Garage and Baseline, all of which played a part in the artist he has become today. 

Being quickly picked up by UK Techno giant Teletech, Joe saw himself rising with the party, and suddenly playing much larger stages, inspiring a cult following along the way. As time went on, Joe found himself leaning more towards the sounds of his home, developing a deep love for the culture and sounds of UK Garage and Hard House, leading to a massive change in direction of both his productions and DJ sets. 

2024 saw multiple appearances for The Warehouse Project, legendary UK festivals like Glastonbury, Parklife and Creamfields and numerous performances further afield, for collectives such as Intercell, Glitch and Boiler Room. Summer in particular resulted in a huge breakthrough for Joe, quickly garnering huge support for his new direction both at home and across the world, with multiple tours across Australia and Asia. 

2025 is set to be a monumental year for Joe, with festival season fast approaching, multiple explosive productions waiting to be released, and an exciting UK tour on the horizon, along with USA, Australia and Asia appearances. 2026 may be the Chinese Year of the Horse, but 2025 is shaping up to be the year of Faster Horses.', 'https://www.awakenings.com/en/artists/faster-horses/382757/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Stef de Haan', 'stef de haan', false, 'Stef de Haan (he/him) is an Amsterdam-based producer, DJ, and founder of De Reünie. Known for his dynamic sets blending intricate percussion, melodic rhythms, and strong, rhythmic sounds, Stef is redefining the electronic music scene with each performance.', 'https://www.awakenings.com/en/artists/stef-de-haan/382760/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('The Tunegirl', 'the tunegirl', false, 'I dreamed of making music back in the 70s. At that me I was an absolute Hard Rock fan and I loved thesound of Status Quo and AC/DC later on. I always wanted to play electric guitar and I kept bugging myparents about it un l they nally bought me a cheap Strat copy and a small amp in a departement store. I was then the guitarist in our school band. We played the songs of our idols and partly our own. No onenew notes, everything by ear. We were well known in our town and had a great me.

Then in the 80s funk and soul music made me sit up and take no ce. This driving groovy sound had done itto me. I was by chance (in the early 80s) Djane in a small disco in our town and played the popular disco,soul and funk hits of the 70s and 80s.That was also the me when i rst got in touch with sythesizers. We s ll had our band and one day we hada keyboard player. He had a Yamaha synth that caught my a en on. And then came the me of synth popwith Depeche Mode, Human League, Duran Duran, just to name a few.

I don''t remember exactly when I rst came aware of techno music. Ar sts like Je Mills, Robert Hood, SteveStoll, Richie Haw n, K.Hand etc. ashed me with their minimalist sound. The sound of the drummachinesthat was so incredibly on point and those blubbing basslines and never heard before sounds andrhythms...outstanding! That''s what I wanted to do. 

But I always torn between Techno (Detroit, Minimal, Acid) and House music (Acid house, Chicage, New York,Vocal, Minimal). I put together a small setup with Atari computer, Steinberg Cubase, Roland D20, Juno 106, TR-707, AkaiS700 and various outboard, mixer and speakers. That''s how it started with electronic music and ended in1999. I sold everything, did nothing for 10 years. This was for family reasons. 

In 2009 it started again, but only in the box. Propellerhead Reason, Ableton Live and so on. That was fun, but I was always dissa s ed with the results.I can''t do arrangements, that''s horror for me. I love to jam and with so ware and controllers I didn''t enjoythat.

So I bought hardware again. Elektrons, Volcas, Roland Airas and some more. But I wasn''t happy with all thegreat gear.I knew that modular synths and eurorack existed, but never believed that this would be something for me.And then it happened: I watched a YT video in which someone was doing techno music with his euroracksystem. I was blown away and immediately excited, but I didnt know how it worked.

I had no idea about the individual modules and their func ons, because I didn''t know how a synth is built,not to men on synthesis.So I rst bought a case. This stood unused in the room for one year, because I didn''t know with whichmodules I shoul start.

A er watching a lot of YT vids and tutorials, I''ve started with the construc on of the system. And I couldmake sounds, but they were far from techno ;)

It was a very long way and I paid a lot of dues. But with the eurorack system I have found my idealinstrument. I have my rst release on Assassin Soldiers Recordings in the middle of may and i am very happy about it.', 'https://www.awakenings.com/en/artists/the-tunegirl/385631/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Adrián Mills', 'adrián mills', false, 'Adrian Mills aka the spanish loco that will make you dance all night with hard sounds like (Early) hardstyle and hardcore, acid- and hard techno mixed with ghetto elements and crazyvocals. He received his first mixer with just twelve years old, which gave him plenty of timeto develop his unique style and sound. Now 24 years old, his tracks and mixes give off a unique type of energy which immerses thecrowd and fills the dancefloor with power and ADRENALINE! Adrian is resident at the infamous gotec club as well as at the rising event series ADRENALINE in Cologne.', 'https://www.awakenings.com/en/artists/adrian-mills/381919/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Ciara Cuvé', 'ciara cuvé', false, 'Twin sister of Clara Cuvé', 'https://www.awakenings.com/en/artists/ciara-cuve/382776/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Azyr', 'azyr', false, 'Azyr is a DJ & Producer who is currently making waves in the industry with his recent productions dominating the scene on a global scale. Based In the North West Of England, Azyr''s musical influence originated from the dark and industrial sound of techno however over the course of two years, Azyr has developed a unique style delving into the Acid, Schranz, Rave, Hard Dance and Psytrance sub genres of techno in his productions and DJ’ing also. Azyr''s sound is driven by energy throughout taking the listener on a journey through fast pace, full throttle, relentlessly hard-hitting techno that is bound to leave the crowd sweating and desperate for more. 

In 2021, Azyr began to make a name for himself in the UK scene, making his debuts in major cities across England & Scotland such as Liverpool; Manchester; Glasgow & Edinburgh and has continued to thrive in 2022, securing bookings from some of the biggest promoters in the scene. In August Azyr made his UK festival and boiler room debut with Teletech and will make his international debut in Paris in September. Azyr’s ambition is to take his sound and skill set to the international stage and preform to people that share his passion for underground music all around the world. Azyr’s music is already doing just that as it is being supported by some of the largest names in the industry such as Paula Temple, Shlømo, 999999999, SNTS, DYEN, Nico Moreno, Tham, Parfait, DLV, Alignment, Lee Ann Roberts, Sara Landry, Lessss, Cassie Raptor, Cera Khin, Cynthia Spiering, Noneoftheabove, Daria Kolosova & more.', 'https://www.awakenings.com/en/artists/azyr/295989/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Charlie Sparks', 'charlie sparks', false, 'Charlie Sparks is all about the energy. Known for emitting an intense gripping aura by seemingly blending Acid, Industrial, Rave, and Psytrance-like grooves. By carefully utilising every aspect of each Charlie is able to create the relentless momentum found in both his productions and performances. His unique hazardous identity has quickly spread and gained acknowledgment from artists such as Amelie Lens, NINETIMESNINE, and many other heavyweights in the game.

It all started during his architecture studies where he delved into the dark, hard-hitting style of techno and quickly came to realise the huge connection between both creative fields. Just like architecture, every aspect of his music is specifically designed to generate certain emotions and control the atmosphere to captivate the listener. As a result, Charlie has been able to design his energy-filled, rhythmic pounding trademark sound which electrifies dance floors across the world.', 'https://www.awakenings.com/en/artists/charlie-sparks/214092/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Kyra Khaldi', 'kyra khaldi', false, 'Kyra Khaldi is a multifaceted artist whose passion for music extends across a wide spectrumof styles and sounds. This versatility shines through in her dynamic DJ sets, where shecarefully balances contrasts and creates harmony between opposites. Her sound is elegantyet raw, sensual yet gritty, trippy but warm. Her music is a reflection of herself bubbly butmodest, mysterious but outspoken.

Beyond her work as a DJ and producer, Kyra also co-runs the dance label ForesightRecords together with DJ duo Mixolydian, a platform dedicated to releasing music from moreundiscovered but highly talented electronic artists.

In a short time, Kyra has graced the stages of some of the Netherlands most iconic venuesand festivals, including Lowlands, Wildeburg, Raum, Shelter, LoFi, Bret, Tilla Tec, amongmany others.', 'https://www.awakenings.com/en/artists/kyra-khaldi/382876/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Aldonna', 'aldonna', false, 'Aldonna is a Melbourne-born, Brussels based DJ, producer, and label curator celebrated for her discerning ear and instinctive touch as a selector and producer. Her sound captures the euphoric pulse of the ’90s and early 2000s, finding harmony between House & Progressive, with a refined vinyl sensibility.

Following a landmark year in 2024 that saw the launch of her vinyl imprint Re-Leaf Records with her third EP which ''Female Fatale'', an instant sell out, and acclaimed international tours across 3 continents, 2025 saw Aldonna’s rise continue with fresh releases on label’s such as Semi Delicious, and recent performances at institutions such as Fabric London & Panorama Bar.

As she continues to expand her global footprint, Aldonna’s vision grows ever clearer — a boundary-pushing artist shaping the next chapter of modern club culture. Free-spirited with an unwavering approach to her vision across all disciplines, the Producer, DJ and Label Curator propels herself deeper into her practice. Lighting up dance floors and crowds with her infectious energy, love and joy for her craft.', 'https://www.awakenings.com/en/artists/aldonna/384395/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Main phase', 'main phase', false, 'Copenhagen-born DJ/producer and co-founder of ATW Records with Interplanetary Criminal. 

Main Phase boasts an impressive back catalogue with releases on the likes of Warehouse Rave, Shall Not Fade, Dansu Discs, ec2a, Dim Sum Records, Haws, 3 Feet Deep, Hardline Sounds, Nerang Recordings, Project 90, Petrola 80 and Practical Rhythms.

Combining elements of jungle, breaks, dubstep, 2-step and more, Main Phase is proof that the current underground resurgence of the UK sound reaches further than the British Isles.', 'https://www.awakenings.com/en/artists/main-phase/385259/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Milion', 'milion', false, 'Milion, the Netherlands-born DJ and producer raised between Switzerland and Australia, is carving out a unique space with his high-energy fusion of house and garage. Presenting a new approach to club music that confidently moves between UK Garage and progressive sounds, his fast-paced cuts behind the decks, alongside increasingly in-demand productions, have quickly established him as a standout name in Amsterdam’s underground.After growing up abroad, Milion found early inspiration in Rotterdam’s raw, industrial scene — a fitting foundation for an artist whose sound balances grit with precision. It wasn’t long before he set his sights on Amsterdam, the beating heart of Dutch underground culture.

2025 marked a breakout year. Milion stepped onto the main stage at DGTL Festival, delivering a high-impact set that showcased the full spectrum of his sound — from driving house to UKG-laced euphoria. That same year, he made his debut at Lowlands Festival, further cementing his status as one of the Netherlands’ most exciting rising selectors.

His productions and DJ sets have drawn recognition from respected names including Job Jobse, Eris Drew, Chris Stussy, Interplanetary Criminal, Laidlaw, and The Ghost, with releases spanning Hardline, Homegrown, EC2A, and Planet Strangelove. Expanding his vision beyond the booth, Milion has also formed OG Records — a crew and platform steadily carving out space in Amsterdam’s house and UKG landscape', 'https://www.awakenings.com/en/artists/million/199701/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Emvae', 'emvae', false, 'Groningen-based Emvae blends house, disco, and minimal to create joyful, soulful dancefloor moments. 
His sets, inspired by dancers and fellow artists, blend groovy house beats with influences from disco, soul, garage, minimal, and more, aiming to create joyful, freeing experiences.', 'https://www.awakenings.com/en/artists/emvae/362091/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Moxes', 'moxes', false, 'When Moxes steps up, the energy never dips—it only soars. Known for dropping one house banger after another, he seamlessly blends infectious basslines with progressive grooves, always keeping the vibe fresh and electric. Sure, you might wish he was tearing up the dance floor beside you, but with Moxes at the helm, the booth and the dance floor become one pulsating force.

						Big hugs, bigger smiles, and massive tracks—that''s the Moxes trifecta. With a meteoric rise to prominence, this charismatic artist commands the decks with ease, navigating through a myriad of styles and moods. From house and trance-infused party anthems to unexpected breakbeats and powerful bass drops that shake the subs, Moxes is the Swiss Army knife of energy, bringing versatility and vibrance wherever he plays.

						Catch Moxes taking you on a ride that leaves no foot standing still, turning every night into an unforgettable journey.', 'https://www.awakenings.com/en/artists/moxes/375456/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Helena Lauwaert', 'helena lauwaert', false, 'Helena Lauwaert is a young and upcoming dj from Ghent. She defines herself by combining different styles, such as: groovy techno, hard house & speed house.

Youthful and emerging, Helena Lauwaert seamlessly blends a wide variety of genres including hard house, speed house and hardgroove together during her DJ-performances. Helena Lauwaert’s genre-fluid music selection and cleverness behind the decks already cleared the roads to Fuse, Exhale, Kompass, Extrema Outdoor, Paradise City and more. A record that clearly indicates she has a bright future ahead.', 'https://www.awakenings.com/en/artists/helena-lauwaert/384835/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Sam Alfred', 'sam alfred', false, 'As Australia rises as a global leader in electronic music, a few distinct mastheads of the form emerge. Sam Alfred is one of those, a fastidious DJ and precocious artist pushing the sound of Australian dance music and cultivating its growth in the global circuit. With sold-out shows across Asia, Europe and Australia, a memorable Boiler Room at AVA Festival in Belfast, and a number of well-rinsed releases under his belt, Sam Alfred is in a position of dominance.

Stylistically, Sam Alfred is a conduit for the modern resurgence of 90s house, garage and techno. His music is large, thumping four-on-the-floor bangers suitable for massive sound systems and parties, akin to collaborators and friends X CLUB., LB aka LABAT, and SWIM. 2024’s Roadblocks EP, out on global tastemaker label Running Back, has moved the needle far in Sam Alfred’s favour, five flavourful house tracks that have moved dancefloors across the world. A thrilling collaboration with Kyle Starkey and acclaimed remix of Royel Otis later, 2024 has seen Sam Alfred placed firmly in dance music canon.

The Egypt-born, Sudanese DJ’s performances epitomise his distinct sound, euphoric and maximal sets that absorb his crowds into one singular mass. Dominating the Australian circuit across stages at Pitch Music & Arts, Strawberry Fields and Beyond the Valley, Sam Alfred is now taking to festivals worldwide after a particularly successful European tour in 2024. As he effortlessly navigates jazz-tipped house, deep cuts, and UK garage, all with a distinct 90s lens, dance music feels brighter with Sam Alfred.', 'https://www.awakenings.com/en/artists/sam-alfred/385626/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Hannecart', 'hannecart', false, 'Hannecart is a force on and off the decks, carrying a raw taste in music which is impossible to ignore. Born Lorena Hannecart from the Dominican Republic, the Liquids resident and member of the VBX roster has a deep connection with music. With grandparents who toured as classical musicians and parents who took pleasure in sharing music at home, it wasn’t long before Lorena’s own musical identity started to take shape. 
Her early days behind the decks were nurtured by the local collective Zoresti, a creative hub on her home island responsible for bringing international talent to the Dominican Republic. Zoresti gave her a platform and the space to grow as an artist. In 2020, Hannecart followed a deeper call—back to her roots.
Fast forward to 2025, and Hannecart is no stranger to the capital city of the Netherlands, where her craft has been forming with undeniable force. She’s been landing coveted spots around amsterdam at revered parties like Slapfunk and VBX– two of the promoters she has identified with the most musically since her move to the lowlands. Her sets are a seamless journey, effortlessly weaving between house, techno, minimal, electro, and breaks, tailored perfectly for every changing moment. It’s not just her selection that turns heads, but her presence—she moves with a sixth-sense for timing, leaving dance floors captivated and always hungry for more.
With performances at Lofi, Shelter, and Thuishaven under her belt, Hannecart is on a path of musical growth.', 'https://www.awakenings.com/en/artists/hannecart/372986/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Paranoid London', 'paranoid london', false, 'Few acts have had such a profound impact on the evolution ofclub culture, but Paranoid London is undoubtedly one of them. When they burst onto the scene over a decade ago, their raw, unfiltered sound was sofresh it sparked a wave of imitators. Their live performances, too, revolutionized the scene, inspiringa shift toward more dynamic, immersive experiences.

From headlining legendary festivals like Glastonbury (SilverHayes, Block9, & Shangri-La), Sonar, Dekmantel, and Movement Detroit, to gracing iconic clubs like Fabric, Panorama Bar, Lux Fragil (Lisbon), and Pacha (Ibiza), Paranoid London has taken their electrifying sound to every corner of theglobe. Their reach extends from NYC’s Good Room to LA’s Lights Down Low, and from Amsterdam’s DGTL to San Francisco’s Sunset Campout.

Now pushing the envelope even further, they’ve embraced a "hybrid" DJ style, blending live synths, effects, and sequenceswith decks to create a constantly evolving, high-energyperformance that never stops moving forward. 

And with their revamped full live show, now enhanced withvisuals from the acclaimed Bob Jaroc (Fatboy Slim, Dua Lipa, Duke Dumont), Paranoid London is taking things to the nextlevel—seriously, they’re not messing around.

Three critically acclaimed albums, countless 12" singles, andedits have ensured they remain a fixture in DJs'' record boxes,on stages, and in booths around the world.', 'https://www.awakenings.com/en/artists/paranoid-london/382763/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Doudou MD', 'doudou md', false, 'Currently one of the most in-demand selectors of Amsterdam, with upcoming performances at Dimensions Croatia, the Pine stage at Unum Albania, the Loft in Manchester and Breakfast Club Amsterdam.

After spending her early (club) years in Utrecht and Amsterdam, surrounded by her forever cherished Slapfunk and VBX brothers, she spent 5 years in Berlin. Here clubs like Berghain, Hoppetosse and Ohm played a big influence on her musical and personal developments. She takes much of her inspiration from artists like Zip, Roman Flügel, Paul Johnson, as well as Steve O’Sullivan and Mr. G.

Back in Amsterdam today, never taking the experience of the dance floor lightly, she fine-tuned her view of the ultimate club experience all over the world. Perfecting this craft is a never-ending process, making her upcoming gigs all the more interesting for both crowd and artist.', 'https://www.awakenings.com/en/artists/doudou-md/382788/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Jennifer Loveless', 'jennifer loveless', false, 'Jennifer Loveless is all heart and a force among the queer powers driving a particular moment in dance music history. The multidisciplinary artist’s creative outputs inhabit the full spectrum of emotion. They tip into the dualities and subtleties that shape the human experience. Whether she’s producing music, DJing, scoring for screen, or writing top lines, Loveless has a versatility that spans cheeky and deep, naughty and nice, delicate and driving. She ventures into unexpected pockets of the zeitgeist to feed her own creativity. At once, Jennifer 

Loveless can tap at your serotonin and pick at emotional scabs. Dance drives her love of club music. JLO is just as comfortable on the dance floor as she is behind the decks which creates an infectious energy and undeniable authenticity. Her emotive, body-pulsing, romping sets span the wide gamut of house and shimmy into techno with a sense of warmth. Loveless adds colour and depth as elation and nostalgia stitch her signature grooves together. This attitude has landed her nods for standout mixes on Truants, Daisychain and Crack Magazine.

As a producer, Loveless is a potent creator who’s dropped five releases within three years. With them, she is
both prolific and acclaimed. Whether it’s psychedelic house, raucous summer anthems, muted beats or heartfelt poems, she’s consistently received ‘Best Of’ recognition across Resident Advisor, Bandcamp and Pitchfork.

‘Pleasure’ was named as one Mixmag’s Best Tracks of the Year and she’s featured in RA’s Art of Production
series and was listed as one of The Guardian’s ‘Artists To Watch’. This recognition, coupled with releases and
affiliations on striking labels like Sex Tags UFO, Planet Euphorique, Butter Sessions, !K7, Future Classic and
Miami Daddy, cement her as an intuitive, yet technical producer.

Loveless has spent decades absorbing and living in various scenes around the globe from Canada to Australia and has been Europe-based since 2021. Her eclectic musical background is what makes her just as skilful at playing heady club nights in Panorama Bar and De School as she is working audiences at festivals like Horst or Pitch Music & Arts. Loveless brings a sense of self-discovery, expansion and meticulousness to her craft leaving hearts and dancefloors aching and racing.', 'https://www.awakenings.com/en/artists/jennifer-loveless/382791/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('DJ Sweet6teen', 'dj sweet6teen', false, 'DJ Sweet6teen, whose real name is Lea Lang, is a DJ from Cologne celebrated for her vibrant performances and a deep love for 90s rave music. Her musical path began with an appreciation for Italo, Eurohouse and Trance, she has since honed her style by blending various genres.

Lea boasts a wide collection of vinyl records and is recognized for her talent in uncovering and showcasing hidden tracks from the 90s and 2000s. She has graced numerous events and venues, including Brandwerk Open Air alongside Lemsn and Jascha Yousefi, as well as radio shows on Rinse France, Kiosk Radio and The Lot Radio.

Her musical approach is diverse, encompassing an array of genres such as house, trance, breakbeat, hardcore and UK garage. She is known for her dynamic sets infused with old-school classics, ensuring her performances are both exciting and nostalgic.', 'https://www.awakenings.com/en/artists/dj-sweet6teen/384544/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Karina Schneider', 'karina schneider', false, 'Karina Schneider, originally from Berlin and now making waves in Amsterdam, has been deeply entrenched in the dynamic world of electronic music since her youth. 

Inspired by the pulsating beats that permeate her hometown, Karina unearthed her true passion for music. Karina''s journey has been profoundly influenced by the raw textures of techno, which she skillfully intertwines with her love for diverse musical genres.', 'https://www.awakenings.com/en/artists/karina-schneider/382770/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('JSPRV35', 'jsprv35', false, 'JSPRV35’s sound is deeply rooted in the late ’90s and early 2000s. A bold influence evident in his vinyl and digital DJ sets, which showcase groovy, loopy old-school techno and electro.

The Dutch DJ and producer has carved out a distinctive style through his releases, channeling the core elements of electronic music that inspire him most. Known for his relentless, timeless, and dynamic approach, JSPRV35 delivers seamlessly blended, high-energy mixes crafted for the dance floor. With releases on respected labels such as KEY Vinyl, Token, and Tar Hallow, he also operates his own imprint, V35 Records, solidifying his position in the scene.', 'https://www.awakenings.com/en/artists/jsprv35/382810/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Toobris', 'toobris', false, 'Toobris grew up in Munich and later moved to Stuttgart for studies, also spending time in Berlin and Amsterdam. The vibrant musical scenes in these cities played a key role in shaping his sound. Known for embracing randomness, his tracks feature unpredictable elements that come together cohesively when heard as a whole. Toobris’ music is soulful, groovy, and bouncy, with basslines that have rhythmic quality that invites movement, complemented by crisp hi-hats and rich percussive textures. With a minimalist approach and a focus on sound design, Toobris creates a unique sonic landscape that feels both intricate and captivating.', 'https://www.awakenings.com/en/artists/toobris/382801/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('UFO95', 'ufo95', false, 'There’s a raw urgency in UFO95’s approach to techno, a sense that each kick and loop is being forged in
real time. The French artist has built his name on a sound that’s both hypnotic and visceral, channeling the
darker pulse of ‘90s and early ‘00s techno while keeping it fiercely present.

						Based in Brussels, and holding a residency at Tresor in Berlin, UFO95 has become a key figure in the new
wave of live performers redefining techno’s boundaries. His sets at institutions like Berghain, Bassiani,
Basement NY, and Tresor are driven by improvisation rather than premeditation: machines breathing,
patterns mutating, energy shifting as he lives each movement of the music.

						On record, his releases for Tresor, WSNWG, MORD, and his co-run label TSSRCT (togther with Hadone, as
the duo Civic Instruction) channel the same stripped, relentless energy that powers his performances.
UFO95’s music isn’t nostalgic, it is a reimagining of techno’s core principles: repetition as hypnosis, rhythm
as resistance, and sound as a form of total immersion', 'https://www.awakenings.com/en/artists/ufo95/382830/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Kameliia', 'kameliia', false, 'Based in Oslo, Kameliia has built her reputation on mysterious, hypnotic and atmospheric techno sets. Her sets are fuelled by driving beats, often characterized by rhythmic sub-basses and reverb-soaked percussion, guiding the dancefloor through a deep musical journey.

Kameliia’s career as a producer has led her to several releases with prestigious labels such as SK_eleven, Token, WSNWG and AMTK+, showcasing her sophisticated and elegant approach to techno. 

With her distinctive sound Kameliia has been captivating the dancefloors at some of the scene’s most respected venues such as Berghain, De School, Fold, Fuse and notable festival appearances include Stone Techno Festival and Berlin Atonal.', 'https://www.awakenings.com/en/artists/kameliia/382804/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Setaoc Mass', 'setaoc mass', false, 'Setaoc Mass is an essential voice in techno and electronic music today. As a DJ, producer and label curator, his vision is bold and clear, rooted as much in techno as it is in IDM, electro and experimental music. 

Setaoc Mass is Sam Coates, an artist born in Manchester, long-since based in Berlin. In 2013, Coates moved from Manchester to Berlin and dedicated himself to music completely. In 2015, Coates launches SK_Eleven, a platform for his own music and "highly personal" project named after his home postal code that remains the primary home for his music. Four years later, SK_Eleven grows into SK_X, an outlet for music from like-minded artists among the best in techno. The project nurtures new talents and fosters a sense of community, actively contributing to the evolution of the techno scene. Then came 2022''s Horror Vacui [SK11010], a debut album that made a clear artistic statement: with Setaoc Mass, techno is just the tip of the iceberg.

As a DJ, Setaoc Mass is a regular on the world''s most hallowed dance floors — from Berghain, Basement and Bassiani to Awakenings, Freedom Festival, Paradigm Festival and more. A devotee of his music''s history with no patience for nostalgia, Coates has absorbed techno''s legacy, and is dedicated to pushing it forward.', 'https://www.awakenings.com/en/artists/setaoc-mass/12057/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Colin Benders', 'colin benders', false, 'Colin Benders is a high-wired artistic spirit, a mind drilled to compose as swiftly as he creates. Over the past seven years, Benders honed an instrument that can fully harness this unique gift for conducting an abundance of sonic elements: the modular synth. From polyphonic, harmony-based pieces to resounding techno sprawls, Benders lives to make music for the here and now, and in turn, unshackle himself from the type of rigid recording-and-live performance cycle many musicians find themselves stuck in. 
Even before touching his first modular synth module, Benders managed to push the possibilities of live music to its utmost limits. His Kyteman Orchestra received myriad accolades, as a velocity of ideas manifested through live performance in unprecedented ways. With so many factors at play – a huge ensemble cast and his thirst for reinvention – it became more and more evident the Utrecht-based composer needed a clean slate of aural expression; one that didn’t involve retracing the already expressed and documented. 
Nosediving into the world of modular synths gave Benders free rein to access and summon feelings directly into sound, down to the absolute details. Writing and performing premeditated compositions became a thing of the past: on his new instrument of choice, Benders opts to improvise via live streaming and online video broadcasts. As a result, he quickly turned heads; more specifically, his uncanny ability to generate fully-formed ideas on-the-fly with a wide array of modules at his behest. 
Over the past few years, Benders has been invited to perform at established festivals and clubs, including Awakenings, Dekmantel, Le Guess Who?, Amsterdam Dance Event and Berghain. Like those regular streaming broadcasts, each of these performances became a unique experience in itself. For now, he is content to interact and explore his music on a day-to-day basis; it''s now expressed as a sincere vocabulary rather than a finished product. And, strangely enough, the modular synth allows Colin Benders to be both engineer and explorer of his own impulsive, highly infectious process.', 'https://www.awakenings.com/en/artists/colin-benders/270/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Dasha Rush', 'dasha rush', false, 'Roots of such sounds partially go back to the early 20th century and rise to significant Art Movements to this day. Dasha likes to push the boundaries of contemporary dance to the limit, encourages experimentation with various musical (and non musical) forms and assembling into deep, slightly dark, and very emotional artistic way of expression. In her strange and twisted world the machines are the protagonists of a neo-romanticism, weaved with human dreams', 'https://www.awakenings.com/en/artists/dasha-rush/310/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Jeans', 'jeans', false, 'Hailing from Holland’s West Coast, JEANS is a powerhouse behind the decks with an uncanny ability to commandeer the dance floor with his characteristic free-flowing style, pushing sonic buttons beyond outer planetary limits. Anything goes and nothing is what it seems as he rifles through his audacious selections while manipulating the pitch faders in every which way. Nobody’s safe from the ‘Ice Cream Man’ when he gets going like an unstoppable train laying down face-melting tekno bangers, breakbeat filth, shamanic, transcendental techno, hints of trance and anything else that gets the job done. However, don’t be fooled by his mischievous smile because he’s got a tender side too and when you least expect it, he will drop some cosmic ambient or laid-back dub reggae on you and it will be exactly what you need at that moment.

Emerging from The Hague’s hardcore and jungle scene with a deep love for raw 90’s Hip Hop, Memphis rap, Dub and Raggamuffin, JEANS ultimately expanded into the realms of tekno, techno, breakbeat, goa and trance but stays noticeably true to his roots in his sets. His tenacity to push the limits and willingness to challenge the crowd has gained him widespread praise, a residency at Het Magazijn and the role of head booker at PIP Den Haag. He spends his downtime jamming on drum machines and producing in his studio while also reinforcing his own lable Oracle Bones. With a tongue-in-cheek attitude and always on the grind, JEANS is not to be underestimated.', 'https://www.awakenings.com/en/artists/jeans/75609/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Spekki Webu', 'spekki webu', false, 'Versatile, exquisite, and resourceful - elements that shape the limitless possibilities of master spellbinder Spekki Webu. Hailing from the unpretentious city of Delft in The Netherlands, this conceptual centipede continues to create an ethereal realm of its own through multiple artistic outlets. Guided by an ethos gained through his involvement in the gabber and tekno movement, Spekki Webu cultivates a trademark sound that can be described as bewitching, persistent, and ritualistic. Whether it is his psychedelic DJ sets, mental live performances, or stellar music productions, the mysterious chief mind expander deconstructs time and space with fierce precision and tactility.

Besides translating his philosophical beliefs on spiritualism throughout his own work, he manifests this vision on electronic music through his Mirror Zone label and Optic Portal sublabel. On a constant quest to explore the unknown, his studio-binging sessions resulted in releases on worldwide respected labels such as Amniote and Positive Source. While balancing on the cross-border of tribalism, experiment, and rhythm - the broad musical spectrum of this lysergic gatekeeper drags you into a wormhole that goes beyond the here and now, captivating listeners into a deep layered state of introspective hypnotism. Escape the simulated reality and delve into the unknown depths of your mind with Mirror Zone head honcho Spekki Webu.', 'https://www.awakenings.com/en/artists/spekki-webu/213895/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

  INSERT INTO artists (name, sort_name, is_collective, bio, source_url)
  VALUES ('Woody92', 'woody92', false, 'As a DJ, his expertly curated and characteristic sets deviate from the norm, exploring psychoactive strains of leftfield electronics, hypnotic techno and radiant minimalism. Woody92 previously cemented his singular and sophisticated DJ style at a number of clubs and institutions, but is equally respected for capturing the energy and curiosity of audiences in outsider spaces across his native Netherlands, as well as far beyond. His pristine yet unpredictable mixes have already left a unique musical footprint, establishing a quietly defiant reputation as a musical curator with increasingly rare depth and focus.

Born in the unassuming town of Delft on the West Coast of Holland, the more radical reverberations from neighbouring city The Hague had a subconscious and eventually more explicit effect on his youthful curiosity and creativity. Woody’s dedication to collecting and reinterpreting electronic music is both parallel and complimentary to his education in art, with a particular interest in graphic design, inspired by aesthetics throughout history and culture. The sum total of these passions manifests in Omen Wapta, a new record label and multidisciplinary platform launched by Woody92 in 2021.

Highlighting music and creative projects from an international but close-knit circle of friends and collaborators, Omen Wapta is inspired by communal histories in order to imagine a collaborative future, a ''transitory playground for the imagination'' consisting of a broad spectrum of styles, encompassing fashion lines and design as well as sonic artefacts.With the alchemy of Omen Wapta as the beating heart of his overall vision, Woody92 continues to challenge himself and others, fluidly curating a path to creative enlightenment and a patiently earned catharsis, both in the club and inspired by it.', 'https://www.awakenings.com/en/artists/woody92/382851/')
  ON CONFLICT (sort_name) DO UPDATE SET
    bio = CASE WHEN EXCLUDED.bio IS NOT NULL AND (artists.bio IS NULL OR length(EXCLUDED.bio) > length(artists.bio)) THEN EXCLUDED.bio ELSE artists.bio END,
    source_url = COALESCE(EXCLUDED.source_url, artists.source_url);

